const { randomUUID } = require("crypto");

// ─────────────────────────────────────
// Guards: cart must already be finalized
// ─────────────────────────────────────
if (!Array.isArray($json.cart_items)) {
  throw new Error("Commit requires cart_items");
}

if (
  typeof $json.subtotal_cents !== "number" ||
  typeof $json.tax_cents !== "number" ||
  typeof $json.total_cents !== "number"
) {
  throw new Error("Commit requires canonical totals");
}

if ($json.is_frozen !== true) {
  throw new Error("Commit requires frozen cart state");
}

// ─────────────────────────────────────
// Timestamps
// ─────────────────────────────────────
const now = new Date().toISOString();

// ─────────────────────────────────────
// Persist snapshot (NO LOGIC)
// ─────────────────────────────────────
return {
  cart_id: $json.cart_id || randomUUID(),
  created_at: $json.created_at || now,
  updated_at: now,
  status: "OPEN",

  customer_name: $json.customer_name || $json["Name"] || "",
  customer_email: $json.customer_email || $json["Email"] || "",
  customer_phone: $json.customer_phone || $json["Phone Number"] || "",

  cart_items_json: JSON.stringify($json.cart_items),

  subtotal_cents: $json.subtotal_cents,
  tax_cents: $json.tax_cents,
  total_cents: $json.total_cents,

  // ✅ audit + traceability
  pass_index: $json.pass_index || null,
  frozen_pass_index: $json.frozen_pass_index || null,
  freeze_timestamp: $json.freeze_timestamp || null,
};
``

