// ─────────────────────────────────────────────
// 1️⃣ LOAD FULL CATALOGS (EXPLICIT, DETERMINISTIC)
// ─────────────────────────────────────────────
const ITEMS = $items("Get item_id").map(i => i.json);
const VARIANTS = $items("Get variant_id").map(i => i.json);
const MODIFIERS = $items("Get mod_id").map(i => i.json);
const MOD_GROUPS = $items("Get mod_groups").map(i => i.json);

// ─────────────────────────────────────────────
// 2️⃣ READ + NORMALIZE COMMITTED CONTEXT
// IMPORTANT:
// After Merge + Set + commit_stage === true,
// ALL intent (primary + upsell) exists on $json.
// STAGED NODES MUST NOT BE READ HERE.
// ─────────────────────────────────────────────
const primaryRaw = $json;
const upsellRaw = $json; // ✅ FIX — read upsells from canonical payload

// Normalize primary intent
const primary = {
  entree_key:
    typeof primaryRaw.entree_key === "string"
      ? primaryRaw.entree_key
      : null,

  variant_id:
    typeof primaryRaw.variant_id === "string"
      ? primaryRaw.variant_id
      : null,

  modifier_ids:
    Array.isArray(primaryRaw.modifier_ids)
      ? primaryRaw.modifier_ids.filter(x => typeof x === "string")
      : []
};

// Normalize upsell intent
const upsellCtx = {
  upsell_item_ids:
    Array.isArray(upsellRaw.upsell_item_ids)
      ? upsellRaw.upsell_item_ids.filter(x => typeof x === "string")
      : [],

  upsell_selections:
    typeof upsellRaw.upsell_selections === "object" &&
    upsellRaw.upsell_selections !== null
      ? upsellRaw.upsell_selections
      : {}
};

// ─────────────────────────────────────────────
// 3️⃣ HARD VALIDATION — FAIL EARLY
// ─────────────────────────────────────────────
if (!primary.entree_key) {
  throw new Error(
    "STRUCTURAL_RESOLVE_MENU_ROWS: missing primary.entree_key"
  );
}

// ─────────────────────────────────────────────
// 4️⃣ RESOLVE PRIMARY ITEM
// ─────────────────────────────────────────────
const primaryItem = ITEMS.find(
  i =>
    i.item_id === primary.entree_key &&
    typeof i.name === "string" &&
    i.sell_price != null
);

if (!primaryItem) {
  throw new Error(
    `STRUCTURAL_RESOLVE_MENU_ROWS: primary item not found for ${primary.entree_key}`
  );
}

// ─────────────────────────────────────────────
// 5️⃣ RESOLVE PRIMARY VARIANT (OPTIONAL)
// ─────────────────────────────────────────────
const primaryVariant =
  primary.variant_id
    ? VARIANTS.find(v => v.variant_id === primary.variant_id) || null
    : null;

// ─────────────────────────────────────────────
// 6️⃣ RESOLVE PRIMARY MODIFIERS
// ─────────────────────────────────────────────
const primary_modifiers =
  Array.isArray(primary.modifier_ids)
    ? primary.modifier_ids
        .map(id => MODIFIERS.find(m => m.mod_id === id) || null)
        .filter(Boolean)
    : [];

// ─────────────────────────────────────────────
// 7️⃣ RESOLVE UPSELL ITEMS + THEIR MODIFIERS ✅
// (THIS WAS THE MISSING PIECE BEFORE THE FIX)
// ─────────────────────────────────────────────
const upsell_items = upsellCtx.upsell_item_ids.map(upsellItemId => {
  const upsellItem = ITEMS.find(
    i =>
      i.item_id === upsellItemId &&
      typeof i.name === "string" &&
      i.sell_price != null
  );

  if (!upsellItem) {
    throw new Error(
      `STRUCTURAL_RESOLVE_MENU_ROWS: upsell item not found for ${upsellItemId}`
    );
  }

  const selection = upsellCtx.upsell_selections[upsellItemId] || {};

  const variant =
    typeof selection.variant_id === "string"
      ? VARIANTS.find(v => v.variant_id === selection.variant_id) || null
      : null;

  const modifiers =
    Array.isArray(selection.modifier_ids)
      ? selection.modifier_ids
          .map(id => MODIFIERS.find(m => m.mod_id === id) || null)
          .filter(Boolean)
      : [];

  return {
    item: upsellItem,
    variant,
    modifiers
  };
});

// ─────────────────────────────────────────────
// 8️⃣ FINAL CANONICAL OUTPUT
// ─────────────────────────────────────────────
return [
  {
    json: {
      // ✅ Preserve merged execution context
      ...$json,

      // ✅ Fully resolved order structure
      primary_item: primaryItem,
      primary_variant: primaryVariant,
      primary_modifiers,
      upsell_items,

      // ✅ Versioning
      structure_version: 3
    }
  }
];

/**
ells, modifiers, drinks) * PRIMARY_ITEM_INTEGRITY_GUARD — FINAL
 * from overriding an already-selected primary entrée.
 *
 * Side-only passes are allowed.
 */

const input = $json;

// ✅ Locked primary entrée (if any)
const locked_primary =
  typeof input.selected_item_id === "string"
    ? input.selected_item_id
    : null;

// ✅ Currently submitted item (if any)
const submitted_item =
  typeof input.item_id === "string"
    ? input.item_id
    : null;

// ✅ Guard condition:
// - A primary entrée is already locked
// - A different item_id is submitted
// - Submission is NOT from the primary stage
if (
  locked_primary &&
  submitted_item &&
  submitted_item !== locked_primary &&
  input.order_stage !== "primary"
) {
  throw new Error(
    `PRIMARY_ITEM_INTEGRITY_GUARD:
     Locked primary: ${locked_primary}
     Submitted item: ${submitted_item}
     Stage: ${input.order_stage || "unknown"}`
  );
}

// ✅ Pass through unchanged
return input;

/**
 * DERIVE_ITEM_ROLE
 *
 * Purpose:
 * Explicitly tag how this item should be treated
 * based on which workflow branch it came from.
 */

const input = { ...$json };

// Default safety
input.item_role = input.item_role || null;

// Entrée / sides treated as entrée
if (input.order_stage === "primary" || input.order_stage === "modifiers") {
  input.item_role = "primary";
}

// Upsell branch
if (input.order_stage === "upsell") {
  input.item_role = "upsell";
}

return input;

