/**
 * STRUCTURAL_RESOLVE_SIDES_ONLY — CANONICAL
 */

const input = $json;

/* 1️⃣ LOAD CATALOGS */
const ITEMS = $items("Get item_id").map(i => i.json);
const VARIANTS = $items("Get variant_id").map(i => i.json);
const MODIFIERS = $items("Get mod_id").map(i => i.json);

/* 2️⃣ NORMALIZE UPSOLD ITEMS (already merged upstream) */
const incomingIds = Array.isArray(input.upsell_item_ids)
  ? input.upsell_item_ids
  : [];

const upsell_selections =
  typeof input.upsell_selections === "object" && input.upsell_selections
    ? input.upsell_selections
    : {};

/* 3️⃣ RESOLVE UPSELL ITEMS */
const upsell_items = incomingIds.map(item_id => {
  const item = ITEMS.find(
    i =>
      i.item_id === item_id &&
      typeof i.name === "string" &&
      i.sell_price != null
  );

  if (!item) {
    throw new Error(
      `SIDES_ONLY_RESOLVE: item not found or invalid for ${item_id}`
    );
  }

  const selection = upsell_selections[item_id] || {};

  const variant =
    typeof selection.variant_id === "string"
      ? VARIANTS.find(v => v.variant_id === selection.variant_id) || null
      : null;

  const modifiers = Array.isArray(selection.modifier_ids)
    ? selection.modifier_ids
        .map(id => MODIFIERS.find(m => m.mod_id === id) || null)
        .filter(Boolean)
    : [];

  return { item, variant, modifiers };
});

/* ✅ 4️⃣ CANONICALIZE IDS */
const canonicalUpsellIds = upsell_items.map(u => u.item.item_id);

/* 5️⃣ OUTPUT */
return {
  ...input,

  primary_item: null,
  primary_variant: null,
  primary_modifiers: [],

  upsell_item_ids: canonicalUpsellIds,
  upsell_items,

  structure_version: 3
};

const input = $json;

/*
  OUTPUT STRUCTURES — MERGE INTO EXISTING IF PRESENT
*/
const upsell_item_ids = Array.isArray(input.upsell_item_ids)
  ? [...input.upsell_item_ids]
  : [];

const upsell_selections =
  typeof input.upsell_selections === "object" && input.upsell_selections
    ? { ...input.upsell_selections }
    : {};

/*
─────────────────────────────────────────────
HELPERS
─────────────────────────────────────────────
*/
const addUpsellItem = (itemId) => {
  if (!upsell_item_ids.includes(itemId)) {
    upsell_item_ids.push(itemId);
  }
};

/*
─────────────────────────────────────────────
FRIES (PLAIN / LOADED)
─────────────────────────────────────────────
Items, NOT modifiers
*/
const friesValue = input["Plain/Loaded Fries"];
let friesItemId = null;

if (typeof friesValue === "string") {
  if (friesValue.includes("Plain")) friesItemId = "FRIES_PLAIN";
  if (friesValue.includes("Bac'n")) friesItemId = "LOADED_FRIES_BC";
  if (friesValue.toLowerCase().includes("philly chik")) friesItemId = "LOADED_FRIES_PC";
  if (friesValue.toLowerCase().includes("garlic parm")) friesItemId = "LOADED_FRIES_GP";
  if (friesValue.toLowerCase().includes("stek")) friesItemId = "LOADED_FRIES_PS";
}

if (friesItemId) {
  addUpsellItem(friesItemId);

  if (Array.isArray(input["Add Ons"])) {
    upsell_selections[friesItemId] = upsell_selections[friesItemId] || { modifier_ids: [] };

    input["Add Ons"].forEach(label => {
      if (label.includes("Jalap")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_JALAP");
      if (label.includes("Bac")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_BACN");
      if (label.includes("Stek")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_STEK");
      if (label.includes("Chik")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_CHIKN");
    });
  }
}

/*
─────────────────────────────────────────────
SIDE SALAD
─────────────────────────────────────────────
*/
if (input["Greens"]) {
  addUpsellItem("SIDE_SALAD");
}

/*
─────────────────────────────────────────────
COOKIES
─────────────────────────────────────────────
*/
if (input["Sweets"]) {
  addUpsellItem("COOKIES_2");
}

/*
─────────────────────────────────────────────
WATER
─────────────────────────────────────────────
*/
if (input["16 oz Bottled Water"]) {
  addUpsellItem("WATER_16OZ");
}

/*
─────────────────────────────────────────────
JUICE
─────────────────────────────────────────────
*/
if (input["Cold Press Juice"]) {
  let juiceItemId = null;

  if (input["Juice Size"]?.includes("16 oz")) juiceItemId = "JUICE_CP_16";
  if (input["Juice Size"]?.includes("10 oz")) juiceItemId = "JUICE_CP_10";

  if (juiceItemId) {
    addUpsellItem(juiceItemId);

    upsell_selections[juiceItemId] = upsell_selections[juiceItemId] || { modifier_ids: [] };

    if (typeof input["Cold Press Juice"] === "string") {
      if (input["Cold Press Juice"].includes("Green")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_GREEN");
      if (input["Cold Press Juice"].includes("Orange")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_ORANGE");
      if (input["Cold Press Juice"].includes("Sweet")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_SWEET");
    }
  }
}

/*
─────────────────────────────────────────────
FINAL OUTPUT
─────────────────────────────────────────────
*/
return {
  ...input,
  upsell_item_ids,
  upsell_selections,
  item_role: "sides_first"
};
